const raw = $input.item.json;
const data = (raw.data && raw.data[0]) ? raw.data[0] : raw;
return {
  json: {
    fg_value: (data.value !== undefined && data.value !== null && data.value !== '') ? Number(data.value) : 50,
    fg_classification: (data.value_classification !== undefined && data.value_classification !== '') ? data.value_classification : 'Neutral'
  }
