const raw = $input.item.json;
let rsi = 50, currentVol = 0, avgVol = 1;
try {
  const result = raw.chart && raw.chart.result && raw.chart.result[0];
  if (result) {
    const closes = result.indicators.quote[0].close || [];
    const volumes = result.indicators.quote[0].volume || [];
    const period = 14;
    if (closes.length >= period + 1) {
      let gains = 0, losses = 0;
      for (let i = closes.length - period; i < closes.length; i++) {
        const diff = closes[i] - closes[i - 1];
        if (diff > 0) gains += diff;
        else losses += Math.abs(diff);
      }
      const avgGain = gains / period;
      const avgLoss = losses / period;
      if (avgLoss === 0) { rsi = 100; }
      else { const rs = avgGain / avgLoss; rsi = Math.round(100 - (100 / (1 + rs))); }
    }
    const validVols = volumes.filter(v => v !== null && v !== undefined);
    if (validVols.length > 0) {
      currentVol = validVols[validVols.length - 1] || 0;
      const last20 = validVols.slice(-20);
      avgVol = last20.reduce((a, b) => a + b, 0) / last20.length || 1;
    }
  }
} catch(e) {}
const volRatio = currentVol / avgVol;
return {
  json: {
    tech_rsi: rsi,
    tech_volume_ratio: Math.round(volRatio * 100) / 100
  }
};

const items = $input.all();
const merged = items.reduce((acc, item) => Object.assign(acc, item.json), {});
return [{ json: merged }];

const d = $input.item.json;
const fgRaw = Number(d.fg_value || 50);
const fearGreed = Math.min(100, Math.max(0, fgRaw));
const rsiRaw = Number(d.tech_rsi || 50);
const rsiScore = Math.min(100, Math.max(0, rsiRaw));
const volRatioRaw = Number(d.tech_volume_ratio || 1);
const volumeScore = Math.min(100, Math.max(0, (volRatioRaw - 1) * 50 + 50));
const sentimentScore = Math.round(fearGreed * 0.4 + rsiScore * 0.4 + volumeScore * 0.2);
let label = 'Neutral';
if (sentimentScore >= 75) label = 'Strong Bullish';
else if (sentimentScore >= 60) label = 'Bullish';
else if (sentimentScore <= 25) label = 'Strong Bearish';
else if (sentimentScore <= 40) label = 'Bearish';
return {
  json: {
    market_sentiment_score: sentimentScore,
    market_sentiment_label: label,
    fear_greed: fearGreed,
    fg_classification: d.fg_classification || 'Neutral',
    rsi_score: rsiScore,
    volume_score: Math.round(volumeScore),
    volume_ratio: d.tech_volume_ratio || 1
  }
};

const d = $input.item.json;
const growthRate = 0.10;
const discountRate = 0.12;
const terminalMultiple = 15;
const fcfPerShare = d.free_cash_flow / (d.shares_outstanding || 1);
let dcfValue = 0;
for (let year = 1; year <= 10; year++) {
  const projectedFCF = fcfPerShare * Math.pow(1 + growthRate, year);
  dcfValue += projectedFCF / Math.pow(1 + discountRate, year);
}
const terminalValue = (fcfPerShare * Math.pow(1 + growthRate, 10) * terminalMultiple) / Math.pow(1 + discountRate, 10);
const intrinsicValue = Math.round(dcfValue + terminalValue);
const marginOfSafety = d.price > 0 ? parseFloat((((intrinsicValue - d.price) / d.price) * 100).toFixed(2)) : 0;
return {
  ...d,
  intrinsic_value: intrinsicValue,
  margin_of_safety: marginOfSafety,
  fcf_per_share: parseFloat(fcfPerShare.toFixed(2))
};

const items = $input.all();
const merged = items.reduce((acc, item) => Object.assign(acc, item.json), {});
return [{ json: merged }];

const ticker = $('Webhook').first().json.body.ticker || 'UNKNOWN';
const eps             = $input.first().json.eps              || 0;
const bookValue       = $input.first().json.book_value       || 0;
const sharesOut       = $input.first().json.shares_outstanding || 1;
const netIncome       = $input.first().json.net_income       || 0;
const forwardPE       = $input.first().json.forward_pe       || 0;
const profitMargins   = $input.first().json.profit_margin    || 0;
const divPerShare     = $input.first().json.div_per_share    || 0;
const enterpriseValue = $input.first().json.enterprise_value  || 0;
const weekChange52    = $input.first().json.week_change_52   || 0;
const price            = $input.last().json.price            || 0;
const totalDebt        = $input.last().json.total_debt       || 0;
const totalRevenue     = $input.last().json.total_revenue    || 1;
const ebitda           = $input.last().json.ebitda           || 0;
const debtToEquity     = $input.last().json.debt_to_equity   || 0;
const grossProfits     = $input.last().json.gross_profits    || 0;
const earningsGrowth   = $input.last().json.earnings_growth  || 0;
const revenueGrowth    = $input.last().json.revenue_growth   || 0;
const grossMargins     = $input.last().json.gross_margins    || 0;
const ebitdaMargins    = $input.last().json.ebitda_margins   || 0;
const operatingMargins = $input.last().json.operating_margins || 0;
const totalCash        = $input.last().json.total_cash       || 0;
const analystTarget    = $input.last().json.analyst_target   || 0;
const recommendationKey = $input.last().json.recommendation  || 'none';
const numAnalysts      = $input.last().json.num_analysts     || 0;
const shareholdersEquity = bookValue * sharesOut;
const roe = shareholdersEquity > 0 ? parseFloat(((netIncome / shareholdersEquity) * 100).toFixed(2)) : 0;
const roa = enterpriseValue > 0 ? parseFloat(((netIncome / enterpriseValue) * 100).toFixed(2)) : 0;
const freeCashFlow  = Math.round(ebitda * 0.75);
const dividendsPaid = Math.round(divPerShare * sharesOut);
const netCash       = totalCash - totalDebt;
const analystUpside = price > 0 && analystTarget > 0 ? parseFloat((((analystTarget - price) / price) * 100).toFixed(2)) : 0;
const pe = eps > 0 ? parseFloat((price / eps).toFixed(2)) : 999;
const pb = bookValue > 0 ? parseFloat((price / bookValue).toFixed(2)) : 999;
const debtToIncome = netIncome > 0 ? parseFloat((totalDebt / netIncome).toFixed(2)) : 999;
return {
  ticker, price, eps, net_income: netIncome,
  profit_margin: profitMargins, earnings_growth: earningsGrowth, revenue_growth: revenueGrowth,
  book_value: bookValue, forward_pe: forwardPE, roe, roa,
  free_cash_flow: freeCashFlow, dividends_paid: dividendsPaid,
  total_debt: totalDebt, total_cash: totalCash, net_cash: netCash,
  debt_to_equity: debtToEquity, debt_to_income: debtToIncome,
  total_revenue: totalRevenue, ebitda,
  gross_profits: grossProfits, gross_margins: grossMargins,
  ebitda_margins: ebitdaMargins, operating_margins: operatingMargins,
  shares_outstanding: sharesOut, div_per_share: divPerShare,
  analyst_target: analystTarget, analyst_upside: analystUpside,
  recommendation: recommendationKey, num_analysts: numAnalysts,
  week_change_52: weekChange52, pe_ratio: pe, price_to_book: pb
};

