const rawOutput = item.output || item.text || item.response || item.message || (item.choices && item.choices[0]?.message?.content) || '';
let parsed = {};
try {
  const cleaned = rawOutput.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  parsed = JSON.parse(cleaned);
} catch(e) {
  parsed = { score: 50, verdict: 'HOLD', key_positives: ['Unable to parse AI response'], key_concerns: ['Parse error'], reasoning: 'Parse error. Raw: ' + rawOutput.substring(0, 200) };
}
const result = { _base_str: item._base_str };
result[persona + '_score']     = parsed.score     || 50;
result[persona + '_verdict']   = parsed.verdict   || 'HOLD';
